// Load roster.yml and extract Team Lead channel and Discord ID.
const fs = require('fs');
const yaml = require('js-yaml');
const path = process.env.ROSTER_CONFIG_PATH || '/data/roster.yml';
let roster;
try {
  roster = yaml.load(fs.readFileSync(path, 'utf8'));
} catch (e) {
  throw new Error('TL Listener: cannot load roster.yml: ' + e.message);
}
return [{
  json: {
    team_lead_channel_id: roster.team_lead_channel_id,
    team_lead_discord_id: roster.team_lead.discord_id,
    client_channel_id: roster.client_channel_id
  }
}];

// Filter messages to unprocessed ones from the Team Lead only.
// Cursor-based deduplication ensures each message is processed exactly once.
const messages = $node['Fetch Recent Channel Messages'].json;
const rosterData = $node['Load Roster'].json;
const teamLeadDiscordId = rosterData.team_lead_discord_id;
const lastMsgResult = $input.first().json;
const lastMsgId = lastMsgResult && lastMsgResult.value_json ? (typeof lastMsgResult.value_json === 'string' ? lastMsgResult.value_json : lastMsgResult.value_json) : null;

if (!Array.isArray(messages) || messages.length === 0) {
  return [];
}

// Filter to TL messages newer than last processed
const filtered = messages.filter(m => {
  if (m.author && m.author.id === teamLeadDiscordId) {
    if (!lastMsgId) return true; // No cursor yet — seed with current, process nothing
    return m.id > lastMsgId;
  }
  return false;
});

// Compute new highest ID from all messages (not just TL's)
const allIds = messages.map(m => m.id);
const newHighestId = allIds.reduce((a, b) => (a > b ? a : b), allIds[0]);

if (!lastMsgId) {
  // First run: seed cursor and stop
  return [{ json: { seed_only: true, new_highest_id: newHighestId, filtered: [] } }];
}

if (filtered.length === 0) {
  return [];
}

const highestFiltered = filtered.map(m => m.id).reduce((a, b) => (a > b ? a : b), filtered[0].id);
return filtered.map(m => ({
  json: {
    message_id: m.id,
    content: m.content,
    author_id: m.author.id,
    team_lead_channel_id: rosterData.team_lead_channel_id,
    team_lead_discord_id: teamLeadDiscordId,
    client_channel_id: rosterData.client_channel_id,
    new_highest_id: newHighestId
  }
}));

// Classify each message into a command branch.
const content = ($json.content || '').trim();
const lower = content.toLowerCase();
let command;
if (lower.startsWith('!report')) {
  command = 'report';
} else if (lower.startsWith('!approve ')) {
  command = 'approve';
} else if (lower.startsWith('!reject ')) {
  command = 'reject';
} else if (lower.startsWith('!edit ')) {
  command = 'edit';
} else if (lower.startsWith('!help')) {
  command = 'help';
} else if (lower.startsWith('!explain')) {
  command = 'explain';
} else if (lower.startsWith('!welcome')) {
  command = 'welcome';
} else {
  command = 'unrecognized';
}
return [{ json: { ...$json, command } }];

// Branch B: Parse draft ID from '!approve <draft_id>'
const content = ($json.content || '').trim();
const parts = content.split(/\s+/);
const draftId = parts[1] || '';
// Basic UUID validation
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(draftId)) {
  throw new Error(`Invalid draft ID format: '${draftId}'. Expected a UUID.`);
}
return [{ json: { ...$json, draft_id: draftId } }];

// Branch C: Parse draft ID from '!reject <draft_id>'
const content = ($json.content || '').trim();
const parts = content.split(/\s+/);
const draftId = parts[1] || '';
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(draftId)) {
  throw new Error(`Invalid draft ID format: '${draftId}'. Expected a UUID.`);
}
return [{ json: { ...$json, draft_id: draftId } }];

// Branch D: Parse draft ID and revised text from '!edit <draft_id> <text>'
const content = ($json.content || '').trim();
const spaceAfterEdit = content.indexOf(' ');
if (spaceAfterEdit === -1) throw new Error('!edit requires: !edit <draft_id> <revised_text>');
const remainder = content.slice(spaceAfterEdit + 1).trim();
const secondSpace = remainder.indexOf(' ');
if (secondSpace === -1) throw new Error('!edit requires both a draft_id and revised text.');
const draftId = remainder.slice(0, secondSpace).trim();
const revisedText = remainder.slice(secondSpace + 1).trim();
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(draftId)) {
  throw new Error(`Invalid draft ID format: '${draftId}'. Expected a UUID.`);
}
if (!revisedText) {
  throw new Error('Revised text cannot be empty.');
}
return [{ json: { ...$json, draft_id: draftId, revised_text: revisedText } }];

// Validate: status=pending, correct approver, not expired.
// Merge upstream context from the parse node.
const draft = $input.first().json;
const teamLeadDiscordId = $node['Load Roster'].json.team_lead_discord_id;
const tlChannelId = $node['Load Roster'].json.team_lead_channel_id;
const draftId = $node['Branch B — Parse Draft ID (Approve)'].json.draft_id;

if (!draft || !draft.id) {
  throw new Error(`Draft ${draftId} not found.`);
}
if (draft.status !== 'pending') {
  throw new Error(`Draft ${draftId} is not pending (current status: ${draft.status}). No action taken.`);
}
if (draft.approver_discord_id !== teamLeadDiscordId) {
  throw new Error(`Draft ${draftId} is not assigned to you for approval.`);
}
if (new Date(draft.expires_at) < new Date()) {
  throw new Error(`Draft ${draftId} has already expired.`);
}
return [{ json: { ...draft, team_lead_channel_id: tlChannelId, draft_id: draftId } }];

// Validate for rejection
const draft = $input.first().json;
const teamLeadDiscordId = $node['Load Roster'].json.team_lead_discord_id;
const tlChannelId = $node['Load Roster'].json.team_lead_channel_id;
const draftId = $node['Branch C — Parse Draft ID (Reject)'].json.draft_id;

if (!draft || !draft.id) {
  throw new Error(`Draft ${draftId} not found.`);
}
if (draft.status !== 'pending') {
  throw new Error(`Draft ${draftId} is not pending (current status: ${draft.status}).`);
}
if (draft.approver_discord_id !== teamLeadDiscordId) {
  throw new Error(`Draft ${draftId} is not assigned to you for approval.`);
}
if (new Date(draft.expires_at) < new Date()) {
  throw new Error(`Draft ${draftId} has already expired.`);
}
return [{ json: { ...draft, team_lead_channel_id: tlChannelId, draft_id: draftId } }];

// Validate for edit+approve
const draft = $input.first().json;
const teamLeadDiscordId = $node['Load Roster'].json.team_lead_discord_id;
const tlChannelId = $node['Load Roster'].json.team_lead_channel_id;
const parseNode = $node['Branch D — Parse Draft ID and Text (Edit)'].json;
const draftId = parseNode.draft_id;
const revisedText = parseNode.revised_text;

if (!draft || !draft.id) {
  throw new Error(`Draft ${draftId} not found.`);
}
if (draft.status !== 'pending') {
  throw new Error(`Draft ${draftId} is not pending (current status: ${draft.status}).`);
}
if (draft.approver_discord_id !== teamLeadDiscordId) {
  throw new Error(`Draft ${draftId} is not assigned to you for approval.`);
}
if (new Date(draft.expires_at) < new Date()) {
  throw new Error(`Draft ${draftId} has already expired.`);
}
return [{ json: { ...draft, team_lead_channel_id: tlChannelId, draft_id: draftId, revised_text: revisedText } }];

// Dispatch delivery based on draft type.
// Reads content_json.text and content_json.metadata from the updated draft.
const draft = $input.first().json;
if (!draft || !draft.id) {
  const tlChannelId = $node['Validate Draft (Approve)'].json.team_lead_channel_id;
  // 0 rows updated means already processed
  return [{ json: { skip: true, message: 'Draft already processed — no action taken.', team_lead_channel_id: tlChannelId } }];
}
const contentJson = typeof draft.content_json === 'string' ? JSON.parse(draft.content_json) : draft.content_json;
return [{ json: {
  draft_id: draft.id,
  type: draft.type,
  content_text: contentJson.text,
  metadata: contentJson.metadata || {},
  team_lead_channel_id: $node['Validate Draft (Approve)'].json.team_lead_channel_id
}}];

// Prepare delivery after edit+approve
const draft = $input.first().json;
if (!draft || !draft.id) {
  const tlChannelId = $node['Validate Draft (Edit)'].json.team_lead_channel_id;
  return [{ json: { skip: true, message: 'Draft already processed — no action taken.', team_lead_channel_id: tlChannelId } }];
}
const contentJson = typeof draft.content_json === 'string' ? JSON.parse(draft.content_json) : draft.content_json;
return [{ json: {
  draft_id: draft.id,
  type: draft.type,
  content_text: contentJson.text,
  metadata: contentJson.metadata || {},
  team_lead_channel_id: $node['Validate Draft (Edit)'].json.team_lead_channel_id
}}];

// Branch F: Extract subject from '!explain <subject>'
const content = ($json.content || '').trim();
const subject = content.replace(/^!explain\s*/i, '').trim();
return [{ json: { ...$json, explain_subject: subject } }];

// Filter logs matching the explain subject. Compose explanation without individual-level data (SC-13).
const subject = $node['Branch F — Parse Explain Subject'].json.explain_subject.toLowerCase();
const logs = $input.all();
const tlChannelId = $node['Load Roster'].json.team_lead_channel_id;
const matching = logs.filter(item => {
  const key = (item.json.key || '').toLowerCase();
  const val = JSON.stringify(item.json.value_json || '').toLowerCase();
  return key.includes(subject) || val.includes(subject);
});
let explanation;
if (matching.length === 0) {
  explanation = `No recent action found matching '${subject}'. The agent has not logged an action with that description.`;
} else {
  const lines = matching.map(item => {
    const v = typeof item.json.value_json === 'string' ? JSON.parse(item.json.value_json) : item.json.value_json;
    return `- Action: ${v.action || 'unknown'} | Draft ID: ${v.draft_id || 'n/a'} | Trigger: ${v.trigger || 'n/a'} | At: ${v.timestamp || 'n/a'}`;
  });
  explanation = `Here are the recent matching actions I took:\n${lines.join('\n')}\n\nI used feature-level signals from GitHub and Jira (no individual attribution) and the project memory. No individual developer data is included in this log. (SC-13)`;
}
return [{ json: { explanation, team_lead_channel_id: tlChannelId } }];
